import{_ as o,o as d,c,ak as a}from"./chunks/framework.D56sOg_b.js";const u=JSON.parse('{"title":"简介","description":"","frontmatter":{"version":"2.0.0"},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1777342039000}'),t={name:"guide/index.md"};function n(i,e,r,s,l,p){return d(),c("div",null,[...e[0]||(e[0]=[a('<h1 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to “简介”">​</a></h1><p><code>Lark Notice Plugin</code> 是一个面向 <code>Jenkins</code> 的构建通知插件，用于将构建过程和结果发送到 <code>Lark</code>、<code>飞书</code>、<code>钉钉</code> 等协作平台。</p><p>插件支持多个通知时机，包括 <code>构建开始</code>、<code>构建中断</code>、<code>构建失败</code>、<code>构建成功</code>、<code>构建不稳定</code> 等。</p><p>插件支持多种消息类型，包括 <code>文本消息</code>、<code>图片消息</code>、<code>群名片消息</code>、<code>富文本消息</code>、<code>卡片消息</code> 和 <code>自定义 JSON 消息</code>。同时支持通过变量和模板自定义通知内容，便于在不同项目中复用。</p><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to “前言”">​</a></h2><p>在持续集成和持续交付场景中，构建结果的及时同步是团队协作的重要环节。<code>Jenkins</code> 作为常用的自动化构建平台，通常承担代码构建、测试执行、制品发布等任务。</p><p>仅依赖 Jenkins 页面查看构建状态，往往难以及时覆盖团队协作需求。将构建结果主动推送到协作平台，可以缩短信息传递路径，提高问题响应效率。<code>Lark Notice Plugin</code> 的目标就是在 Jenkins 与协作平台之间建立稳定、可配置的通知链路。</p><blockquote><p>如果在使用过程中发现问题，或存在需要通过修改源码才能满足的通用需求，欢迎提交 Issue 或 Pull Request。</p></blockquote>',8)])])}const k=o(t,[["render",n]]);export{u as __pageData,k as default};
